INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 10001, "2023/06/30 12:00:00", 1, "2023/09/22 14:59:59", 0.0, 1.47, 1, 1, 2002, 126401, 2, "クローチェ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 10002, "2023/06/30 12:00:00", 2, "2023/09/22 14:59:59", 0.0, 2.15, 2, 1, 2002, 126401, 1, "クローチェ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 10003, "2023/06/30 12:00:00", 2, "2023/09/22 14:59:59", 0.0, 0.0, 1, 1, 2002, 126501, 2, "ライラエル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 10004, "2023/06/30 12:00:00", 1, "2023/09/22 14:59:59", 0.0, 0.0, 2, 1, 2002, 126501, 1, "ライラエル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 10005, "2023/09/15 15:00:00", 2, "2023/12/22 14:59:59", 0.0, 0.0, 1, 2, 2002, 127702, 2, "リンド");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 10006, "2023/09/15 15:00:00", 2, "2023/12/22 14:59:59", 0.0, 0.0, 2, 2, 2002, 127702, 2, "リンド");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 10007, "2023/09/15 15:00:00", 1, "2023/12/22 14:59:59", 0.0, 0.0, 1, 2, 2002, 127802, 1, "ヴルム");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 10008, "2023/09/15 15:00:00", 2, "2023/12/22 14:59:59", 0.0, 6.5, 2, 2, 2002, 127802, 1, "ヴルム");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 10009, "2023/12/15 15:00:00", 2, "2024/03/22 14:59:59", 0.0, 0.0, 1, 3, 2002, 129602, 1, "アネモネ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 10010, "2023/12/15 15:00:00", 2, "2024/03/22 14:59:59", 0.0, 0.0, 2, 3, 2002, 129602, 1, "アネモネ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 10011, "2023/12/15 15:00:00", 1, "2024/03/22 14:59:59", 0.0, 0.0, 1, 3, 2002, 129701, 1, "ネフィ=ネラ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 10012, "2023/12/15 15:00:00", 2, "2024/03/22 14:59:59", 0.0, 6.2, 2, 3, 2002, 129701, 1, "ネフィ=ネラ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 10013, "2024/03/15 15:00:00", 3, "2024/06/22 14:59:59", 0.0, 3.1, 1, 4, 2002, 130301, 5, "カノン");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 10014, "2024/03/15 15:00:00", 3, "2024/06/22 14:59:59", 0.0, 6.15, 2, 4, 2002, 130301, 2, "カノン");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 10015, "2024/03/15 15:00:00", 2, "2024/06/22 14:59:59", 0.0, 0.0, 1, 4, 2002, 130401, 2, "ナーナ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 10016, "2024/03/15 15:00:00", 2, "2024/06/22 14:59:59", 0.0, 3.35, 2, 4, 2002, 130401, 1, "ナーナ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 10017, "2024/06/15 15:00:00", 1, "2024/09/22 14:59:59", 0.0, 0.0, 1, 5, 2002, 130502, 1, "ホウオウ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 10018, "2024/06/15 15:00:00", 2, "2024/09/22 14:59:59", 0.0, 3.18, 2, 5, 2002, 130502, 1, "ホウオウ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 10019, "2024/06/15 15:00:00", 4, "2024/09/22 14:59:59", 0.0, 0.0, 3, 5, 2002, 130503, 4, "ホウオウ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 10020, "2024/06/15 15:00:00", 1, "2024/09/22 14:59:59", 0.0, 4.9, 1, 5, 2002, 123301, 2, "ネア");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 10021, "2024/06/15 15:00:00", 1, "2024/09/22 14:59:59", 0.0, 4.8, 2, 5, 2002, 123301, 2, "ネア");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 10022, "2024/09/15 15:00:00", 3, "2024/12/22 14:59:59", 0.0, 4.922, 1, 6, 2002, 133301, 1, "カリザ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 10023, "2024/09/15 15:00:00", 3, "2024/12/22 14:59:59", 0.0, 9.638, 2, 6, 2002, 133301, 5, "カリザ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 10024, "2024/09/15 15:00:00", 1, "2024/12/22 14:59:59", 0.0, 2.88, 1, 6, 2002, 133401, 2, "ミーア");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 10025, "2024/09/15 15:00:00", 5, "2024/12/22 14:59:59", 0.0, 4.818, 2, 6, 2002, 133401, 1, "ミーア");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 10026, "2024/12/15 15:00:00", 2, "2025/03/22 14:59:59", 0.0, 1.78, 1, 7, 2002, 133002, 1, "グレイス");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 10027, "2024/12/15 15:00:00", 1, "2025/03/22 14:59:59", 0.0, 6.15, 2, 7, 2002, 133002, 7, "グレイス");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 10028, "2024/12/15 15:00:00", 6, "2025/03/22 14:59:59", 0.0, 4.28, 1, 7, 2002, 133102, 2, "ヴァイオレット");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 10029, "2024/12/15 15:00:00", 1, "2025/03/22 14:59:59", 0.0, 0.0, 2, 7, 2002, 133102, 1, "ヴァイオレット");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 10030, "2025/03/15 15:00:00", 2, "2025/06/23 14:59:59", 0.0, 5.53, 1, 8, 2002, 136902, 1, "ルルィ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 10031, "2025/03/15 15:00:00", 9, "2025/06/23 14:59:59", 0.0, 6.05, 2, 8, 2002, 136902, 7, "ルルィ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 10032, "2025/03/15 15:00:00", 2, "2025/06/23 14:59:59", 0.0, 0.0, 1, 8, 2002, 137001, 1, "デュラン");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 10033, "2025/03/15 15:00:00", 2, "2025/06/23 14:59:59", 0.0, 0.0, 2, 8, 2002, 137001, 1, "デュラン");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "おう\n好きなもん持ってきな", 10034, "2025/06/16 15:00:00", 2, "2025/09/23 14:59:59", 0.0, 0.0, 1, 9, 2002, 135902, 2, "サツキ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 10035, "2025/06/16 15:00:00", 1, "2025/09/23 14:59:59", 0.0, 4.935, 2, 9, 2002, 135902, 6, "サツキ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 10036, "2025/06/16 15:00:00", 2, "2025/09/23 14:59:59", 0.0, 7.441, 1, 9, 2002, 135802, 5, "ユキノ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 10037, "2025/06/16 15:00:00", 7, "2025/09/23 14:59:59", 0.0, 0.0, 2, 9, 2002, 135802, 7, "ユキノ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 10038, "2025/09/16 15:00:00", 2, "2025/12/22 14:59:59", 0.0, 2.295, 1, 10, 2002, 130901, 2, "クルル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 10039, "2025/09/16 15:00:00", 1, "2025/12/22 14:59:59", 0.0, 6.281, 2, 10, 2002, 130901, 6, "クルル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 10040, "2025/09/16 15:00:00", 2, "2025/12/22 14:59:59", 0.0, 5.549, 1, 10, 2002, 137701, 1, "ヴォルガーノ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 10041, "2025/09/16 15:00:00", 3, "2025/12/22 14:59:59", 0.0, 2.64, 2, 10, 2002, 137701, 6, "ヴォルガーノ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 10042, "2025/12/15 15:00:00", 7, "2026/03/23 11:59:59", 0.0, 7.642, 1, 11, 2002, 132801, 4, "ライラエル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 10043, "2025/12/15 15:00:00", 1, "2026/03/23 11:59:59", 0.0, 0.0, 2, 11, 2002, 132802, 1, "ライラエル");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 10044, "2025/12/15 15:00:00", 1, "2026/03/23 11:59:59", 0.0, 0.0, 1, 11, 2002, 134502, 1, "クローチェ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 10045, "2025/12/15 15:00:00", 2, "2026/03/23 11:59:59", 0.0, 3.72, 2, 11, 2002, 134501, 1, "クローチェ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 10046, "2026/03/16 12:00:00", 2, "2026/06/22 11:59:59", 0.0, 4.991, 1, 12, 2002, 138201, 1, "ネフィ＝ネラ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 10047, "2026/03/16 12:00:00", 1, "2026/06/22 11:59:59", 0.0, 3.877, 2, 12, 2002, 138201, 4, "ネフィ＝ネラ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 10048, "2026/03/16 12:00:00", 4, "2026/06/22 11:59:59", 0.0, 1.71, 1, 12, 2002, 136001, 6, "アラクネ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 10049, "2026/03/16 12:00:00", 5, "2026/06/22 11:59:59", 0.0, 5.32, 2, 12, 2002, 136001, 2, "アラクネ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "水着で、店番とか──\n本当、意味がわかりません\n海の家でもないのに…", 10050, "2026/06/15 12:00:00", 9, "2026/09/22 11:59:59", 0.0, 3.727, 1, 13, 2002, 135401, 4, "アネモネ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "──リアみたいに、\nもっと愛想良い接客を…\nいえ──なんでもないです", 10051, "2026/06/15 12:00:00", 7, "2026/09/22 11:59:59", 0.0, 7.213, 2, 13, 2002, 135401, 9, "アネモネ");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "いらっしゃいませー♪\n奉仕活動兼、将来のために\nたくさん働いちゃいます♪", 10052, "2026/06/15 12:00:00", 1, "2026/09/22 11:59:59", 0.0, 1.874, 1, 13, 2002, 135301, 2, "クリア");
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (-470.0, "アルバイトが終わったら\n海に遊びに行きましょう！\nモネちゃんも一緒に♪", 10053, "2026/06/15 12:00:00", 2, "2026/09/22 11:59:59", 0.0, 0.0, 2, 13, 2002, 135301, 2, "クリア");
